export const checkId = 'start-script';
export const name = 'Start Script Present';
export const appliesTo = ['all'];

function isLibraryOrToolRoot(p) {
  if (!p) return false;
  if (p.bin) return true;
  if (p.peerDependencies && Object.keys(p.peerDependencies).length > 0) return true;

  const keywords = (p.keywords || []).map(k => String(k).toLowerCase());
  const name = String(p.name || '').toLowerCase();

  if (name.startsWith('eslint-') || /(plugin|loader|preset)$/.test(name)) return true;
  const segments = name.split('/');
  if (segments.length > 1 && segments[0].startsWith('@') && segments[1] === 'types') return true;

  const hasMain = !!p.main;
  const looksPublished = hasMain && !!(p.types || p.typings || p.publishConfig || (p.files && p.files.length > 0));
  const libKw = keywords.some(k => /\b(library|plugin|tool|framework|loader|preset|middleware|cli|package|module)\b/.test(k));
  if (looksPublished && libKw) return true;

  if (hasMain && keywords.some(k => k.includes('framework')) && keywords.some(k => /\b(server|http|middleware|router|rest|api)\b/.test(k))) {
    return true;
  }

  return false;
}

function isLibraryLikeSubPackage(p) {
  if (isLibraryOrToolRoot(p)) return true;

  const hasMain = !!p.main;
  const looksPublished = hasMain && !!(p.types || p.typings || p.publishConfig || (p.files && p.files.length > 0));
  const appRuntimeDeps = ['next', 'nuxt', 'astro', 'express', 'fastify', 'koa', 'hono', 'nitro', 'serve', 'http-server'];
  const hasAppRuntime = appRuntimeDeps.some(d => d in (p.dependencies || {}));

  if (looksPublished && !hasAppRuntime && !p.scripts?.start) return true;
  return false;
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    if (repoType === 'empty' || !tree || tree.length === 0) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'Empty repo — no start script needed',
        findings: [],
      };
    }

    let pkg = packageJson;
    if (!pkg && files && typeof files.get === 'function') {
      try {
        const raw = await files.get('package.json');
        if (raw) pkg = JSON.parse(raw);
      } catch (e) {
        console.error('Error reading package.json via files.get:', e);
      }
    }

    if (!pkg) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'No package.json found — start script check not applicable',
        findings: [],
      };
    }

    const scripts = pkg.scripts || {};
    const startKeys = ['start', 'serve', 'start:prod'];
    let activeScript = null;

    for (const key of startKeys) {
      if (key in scripts) {
        activeScript = scripts[key];
        break;
      }
    }

    if (activeScript !== null) {
      if (typeof activeScript === 'string' && activeScript.trim().length > 0 && !activeScript.includes('TODO')) {
        return {
          checkId,
          status: 'pass',
          confidence: 'high',
          message: `Start script found: "${activeScript}"`,
          findings: [],
        };
      }
      return {
        checkId,
        status: 'check-it',
        confidence: 'medium',
        message: `Start script may be placeholder: "${activeScript}"`,
        findings: [{ file: 'package.json', issue: 'Start script appears to be a placeholder' }],
      };
    }

    const devDeps = pkg.devDependencies || {};
    const isMonorepo = !!pkg.workspaces ||
      tree.some(p => p === 'pnpm-workspace.yaml') ||
      tree.some(p => p === 'turbo.json') ||
      ['turbo', 'lerna', 'nx'].some(t => t in devDeps) ||
      tree.some(p => p.startsWith('packages/') || p.startsWith('apps/'));

    if (!isMonorepo && isLibraryOrToolRoot(pkg)) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'Library or tool package — start script not required',
        findings: [],
      };
    }

    const hasProcfile = tree.some(p => p === 'Procfile');
    if (hasProcfile) {
      return {
        checkId,
        status: 'pass',
        confidence: 'high',
        message: 'Procfile found — deployment entrypoint present',
        findings: [],
      };
    }

    const dockerfilePath = tree.find(p => p === 'Dockerfile' || p.endsWith('/Dockerfile'));
    if (dockerfilePath) {
      try {
        const df = await files.get(dockerfilePath);
        if (df && /^\s*(CMD|ENTRYPOINT)\s/im.test(df)) {
          return {
            checkId,
            status: 'pass',
            confidence: 'high',
            message: 'Dockerfile with CMD/ENTRYPOINT found — deployment entrypoint present',
            findings: [],
          };
        }
      } catch (e) {
        console.error('Error reading Dockerfile:', e);
      }
    }

    if (isMonorepo) {
      const devScript = scripts.dev;
      if ('dev' in scripts && typeof devScript === 'string' && devScript.trim().length > 3 && !devScript.includes('TODO')) {
        return {
          checkId,
          status: 'pass',
          confidence: 'high',
          message: `Monorepo start script found: "${devScript}"`,
          findings: [],
        };
      }

      let foundSubStart = false;
      let reads = 0;
      const maxReads = 5;
      let subLibCount = 0;
      let subOtherCount = 0;

      const appPrefixes = ['apps/', 'services/'];
      for (const dir of appPrefixes) {
        const subPkgs = tree.filter(p => p.startsWith(dir) && /^[^/]+\/package\.json$/.test(p.slice(dir.length)));
        for (const subPath of subPkgs) {
          if (reads >= maxReads) break;
          reads++;
          try {
            const content = await files.get(subPath);
            if (!content) continue;
            const sub = JSON.parse(content);
            const subScripts = sub.scripts || {};
            const val = subScripts.start || subScripts.serve || subScripts['start:prod'] || subScripts.dev;
            if (typeof val === 'string' && val.trim().length > 0) {
              foundSubStart = true;
              break;
            }
          } catch (e) {
            console.error(`Error reading ${subPath}:`, e);
          }
        }
        if (foundSubStart) break;
      }

      if (foundSubStart) {
        return {
          checkId,
          status: 'pass',
          confidence: 'high',
          message: 'Monorepo — start script found in sub-package',
          findings: [],
        };
      }

      const hasAppPackages = appPrefixes.some(dir => tree.some(p => p.startsWith(dir) && /^[^/]+\/package\.json$/.test(p.slice(dir.length))));
      if (hasAppPackages) {
        return {
          checkId,
          status: 'fail',
          confidence: 'high',
          message: 'App monorepo — no start script found in root or apps/',
          findings: [{ file: 'package.json', issue: 'Missing start script in app monorepo' }],
        };
      }

      const pkgPrefixes = ['packages/'];
      for (const dir of pkgPrefixes) {
        const subPkgs = tree.filter(p => p.startsWith(dir) && /^[^/]+\/package\.json$/.test(p.slice(dir.length)));
        for (const subPath of subPkgs) {
          if (reads >= maxReads) break;
          reads++;
          try {
            const content = await files.get(subPath);
            if (!content) continue;
            const sub = JSON.parse(content);
            const subScripts = sub.scripts || {};
            const val = subScripts.start || subScripts.serve || subScripts['start:prod'] || subScripts.dev;
            if (typeof val === 'string' && val.trim().length > 0) {
              foundSubStart = true;
              break;
            }
            if (isLibraryLikeSubPackage(sub)) {
              subLibCount++;
            } else {
              subOtherCount++;
            }
          } catch (e) {
            console.error(`Error reading ${subPath}:`, e);
          }
        }
        if (foundSubStart) break;
      }

      if (foundSubStart) {
        return {
          checkId,
          status: 'pass',
          confidence: 'high',
          message: 'Monorepo — start script found in sub-package',
          findings: [],
        };
      }

      if (subLibCount > 0 && subOtherCount === 0) {
        return {
          checkId,
          status: 'not-applicable',
          confidence: 'high',
          message: 'Library monorepo — start script not required at root',
          findings: [],
        };
      }

      return {
        checkId,
        status: 'check-it',
        confidence: 'medium',
        message: 'Monorepo — no root start script found (may be in a sub-package)',
        findings: [{ file: 'package.json', issue: 'No root start script — verify individual packages/' }],
      };
    }

    const appRuntimeDeps = ['next', 'nuxt', 'astro', 'express', 'fastify', 'koa', 'hono', 'nitro', 'serve', 'http-server'];
    const hasAppRuntime = appRuntimeDeps.some(d => d in (pkg.dependencies || {}));

    if ((repoType === 'library' || repoType === 'tool' || repoType === 'framework') && !hasAppRuntime) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: `${repoType === 'framework' ? 'Framework' : repoType === 'library' ? 'Library' : 'Tool'} — start script not required`,
        findings: [],
      };
    }

    return {
      checkId,
      status: 'fail',
      confidence: 'high',
      message: 'No start script found in package.json',
      findings: [{ file: 'package.json', issue: 'Missing "start" script — required for deployment' }],
    };
  } catch (err) {
    console.error('start-script specialist error:', err);
    return {
      checkId,
      status: 'check-it',
      confidence: 'low',
      message: `Error during check: ${err.message}`,
      findings: [],
    };
  }
}
